tool_input.content:
import { describe, it, expect } from "vitest";
import type {
  Message,
  CheckpointMessage,
  SessionMetadata,
  CompactionConfig,
  PruningConfig,
  ContinuationVariant,
  CompactionResult,
  PreparedCompactionV2,
  ActualTokenUsage,
  ActualTokenUsageInput,
  ContextUsage,
  TodoItem,
  StructuredState,
  SessionHeaderLine,
  MessageLine,
  CheckpointLine,
  SessionFileLine,
  CompactionSummary,
  CompactionSegment,
  PreparedCompactionSegment,
  PreparedCompaction,
} from "./compaction-types";

describe("compaction-types", () => {
  describe("Message", () => {
    it("should have required fields", () => {
      const msg: Message = {
        role: "user",
        content: "test content",
      };
      expect(msg.role).toBe("user");
      expect(msg.content).toBe("test content");
    });

    it("should allow optional fields", () => {
      const msg: Message = {
        role: "assistant",
        content: "test",
        tool_calls: [{ id: "call_1", type: "function", function: { name: "fn", arguments: "{}" } }],
        tool_call_id: "call_1",
        name: "test",
        annotations: [{ type: "test" }],
      };
      expect(msg.tool_calls).toBeDefined();
      expect(msg.tool_call_id).toBe("call_1");
      expect(msg.name).toBe("test");
      expect(msg.annotations).toBeDefined();
    });

    it("should support all role types", () => {
      const roles: Message["role"][] = ["user", "assistant", "system", "tool"];
      roles.forEach((role) => {
        const msg: Message = { role, content: "test" };
        expect(msg.role).toBe(role);
      });
    });
  });

  describe("CheckpointMessage", () => {
    it("should have required fields", () => {
      const checkpoint: CheckpointMessage = {
        checkpoint: "checkpoint_1",
        timestamp: 1234567890,
      };
      expect(checkpoint.checkpoint).toBe("checkpoint_1");
      expect(checkpoint.timestamp).toBe(1234567890);
    });

    it("should allow optional metadata", () => {
      const checkpoint: CheckpointMessage = {
        checkpoint: "checkpoint_1",
        timestamp: 1234567890,
        metadata: { key: "value" },
      };
      expect(checkpoint.metadata).toEqual({ key: "value" });
    });
  });

  describe("SessionMetadata", () => {
    it("should have required fields", () => {
      const meta: SessionMetadata = {
        id: "session_1",
        created_at: 1234567890,
      };
      expect(meta.id).toBe("session_1");
      expect(meta.created_at).toBe(1234567890);
    });

    it("should allow optional fields", () => {
      const meta: SessionMetadata = {
        id: "session_1",
        created_at: 1234567890,
        continuation_variant: "manual",
        max_turns: 10,
        title: "Test Session",
        description: "Test description",
        tags: ["tag1", "tag2"],
      };
      expect(meta.continuation_variant).toBe("manual");
      expect(meta.max_turns).toBe(10);
      expect(meta.title).toBe("Test Session");
      expect(meta.description).toBe("Test description");
      expect(meta.tags).toEqual(["tag1", "tag2"]);
    });

    it("should support all continuation variants", () => {
      const variants: ContinuationVariant[] = ["manual", "auto-with-replay", "tool-loop"];
      variants.forEach((variant) => {
        const meta: SessionMetadata = {
          id: "session_1",
          created_at: 1234567890,
          continuation_variant: variant,
        };
        expect(meta.continuation_variant).toBe(variant);
      });
    });
  });

  describe("ContinuationVariant", () => {
    it("should accept all valid variants", () => {
      const variants: ContinuationVariant[] = ["manual", "auto-with-replay", "tool-loop"];
      variants.forEach((variant) => {
        expect(variant).toBeDefined();
      });
    });
  });

  describe("CompactionConfig", () => {
    it("should have required fields", () => {
      const config: CompactionConfig = {
        enabled: true,
      };
      expect(config.enabled).toBe(true);
    });

    it("should allow optional pruning config", () => {
      const config: CompactionConfig = {
        enabled: true,
        pruning: {
          enabled: true,
          preserve_recent: 5,
        },
      };
      expect(config.pruning).toBeDefined();
      expect(config.pruning?.enabled).toBe(true);
      expect(config.pruning?.preserve_recent).toBe(5);
    });
  });

  describe("PruningConfig", () => {
    it("should have required fields", () => {
      const pruning: PruningConfig = {
        enabled: true,
      };
      expect(pruning.enabled).toBe(true);
    });

    it("should allow optional fields with defaults", () => {
      const pruning: PruningConfig = {
        enabled: true,
        preserve_recent: 10,
        preserve_checkpoints: 3,
        max_messages_per_checkpoint: 100,
      };
      expect(pruning.preserve_recent).toBe(10);
      expect(pruning.preserve_checkpoints).toBe(3);
      expect(pruning.max_messages_per_checkpoint).toBe(100);
    });

    it("should have default values when optional fields omitted", () => {
      const pruning: PruningConfig = {
        enabled: false,
      };
      // Default values should be applied
      expect(pruning.enabled).toBe(false);
    });
  });

  describe("CompactionResult", () => {
    it("should have required fields", () => {
      const result: CompactionResult = {
        before_token_count: 1000,
        after_token_count: 500,
        messages_removed: 10,
      };
      expect(result.before_token_count).toBe(1000);
      expect(result.after_token_count).toBe(500);
      expect(result.messages_removed).toBe(10);
    });

    it("should allow optional fields", () => {
      const result: CompactionResult = {
        before_token_count: 1000,
        after_token_count: 500,
        messages_removed: 10,
        checkpoints_removed: 2,
        duration_ms: 100,
        preserved_messages: [1, 2, 3],
      };
      expect(result.checkpoints_removed).toBe(2);
      expect(result.duration_ms).toBe(100);
      expect(result.preserved_messages).toEqual([1, 2, 3]);
    });
  });

  describe("PreparedCompactionV2", () => {
    it("should have required fields", () => {
      const compaction: PreparedCompactionV2 = {
        messages: [],
        checkpoints: [],
        metadata: { id: "test", created_at: 1234567890 },
      };
      expect(compaction.messages).toEqual([]);
      expect(compaction.checkpoints).toEqual([]);
      expect(compaction.metadata).toBeDefined();
    });

    it("should allow optional session header", () => {
      const compaction: PreparedCompactionV2 = {
        messages: [],
        checkpoints: [],
        metadata: { id: "test", created_at: 1234567890 },
        session_header: { id: "session_1", created_at: 1234567890 },
      };
      expect(compaction.session_header).toBeDefined();
    });
  });

  describe("ActualTokenUsage", () => {
    it("should have required fields", () => {
      const usage: ActualTokenUsage = {
        prompt_tokens: 100,
        completion_tokens: 50,
        total_tokens: 150,
      };
      expect(usage.prompt_tokens).toBe(100);
      expect(usage.completion_tokens).toBe(50);
      expect(usage.total_tokens).toBe(150);
    });

    it("should allow optional cached tokens", () => {
      const usage: ActualTokenUsage = {
        prompt_tokens: 100,
        completion_tokens: 50,
        total_tokens: 150,
        cached_tokens: 30,
      };
      expect(usage.cached_tokens).toBe(30);
    });
  });

  describe("ActualTokenUsageInput", () => {
    it("should have required fields", () => {
      const input: ActualTokenUsageInput = {
        prompt_tokens: 100,
        completion_tokens: 50,
      };
      expect(input.prompt_tokens).toBe(100);
      expect(input.completion_tokens).toBe(50);
    });

    it("should calculate total_tokens automatically", () => {
      const input: ActualTokenUsageInput = {
        prompt_tokens: 100,
        completion_tokens: 50,
      };
      expect(input.prompt_tokens + input.completion_tokens).toBe(150);
    });
  });

  describe("ContextUsage", () => {
    it("should have required fields", () => {
      const usage: ContextUsage = {
        messages: 10,
        checkpoints: 5,
        total_tokens: 1000,
      };
      expect(usage.messages).toBe(10);
      expect(usage.checkpoints).toBe(5);
      expect(usage.total_tokens).toBe(1000);
    });

    it("should allow optional context tokens", () => {
      const usage: ContextUsage = {
        messages: 10,
        checkpoints: 5,
        total_tokens: 1000,
        context_tokens: 800,
        generation_tokens: 200,
      };
      expect(usage.context_tokens).toBe(800);
      expect(usage.generation_tokens).toBe(200);
    });
  });

  describe("TodoItem", () => {
    it("should have required fields", () => {
      const todo: TodoItem = {
        id: "todo_1",
        content: "Test todo",
        status: "pending",
      };
      expect(todo.id).toBe("todo_1");
      expect(todo.content).toBe("Test todo");
      expect(todo.status).toBe("pending");
    });

    it("should allow optional fields", () => {
      const todo: TodoItem = {
        id: "todo_1",
        content: "Test todo",
        status: "completed",
        priority: "high",
        created_at: 1234567890,
        completed_at: 1234567900,
        metadata: { key: "value" },
      };
      expect(todo.priority).toBe("high");
      expect(todo.created_at).toBe(1234567890);
      expect(todo.completed_at).toBe(1234567900);
      expect(todo.metadata).toEqual({ key: "value" });
    });

    it("should support all status types", () => {
      const statuses: TodoItem["status"][] = ["pending", "in_progress", "completed"];
      statuses.forEach((status) => {
        const todo: TodoItem = { id: "todo_1", content: "test", status };
        expect(todo.status).toBe(status);
      });
    });

    it("should support all priority types", () => {
      const priorities: TodoItem["priority"][] = ["low", "medium", "high"];
      priorities.forEach((priority) => {
        const todo: TodoItem = { id: "todo_1", content: "test", status: "pending", priority };
        expect(todo.priority).toBe(priority);
      });
    });
  });

  describe("StructuredState", () => {
    it("should have required fields", () => {
      const state: StructuredState = {
        todos: [],
      };
      expect(state.todos).toEqual([]);
    });

    it("should allow optional fields", () => {
      const state: StructuredState = {
        todos: [
          { id: "todo_1", content: "Test", status: "pending" },
        ],
        metadata: { key: "value" },
        version: 1,
      };
      expect(state.todos).toHaveLength(1);
      expect(state.metadata).toEqual({ key: "value" });
      expect(state.version).toBe(1);
    });
  });

  describe("SessionHeaderLine", () => {
    it("should have required fields", () => {
      const line: SessionHeaderLine = {
        type: "header",
        id: "session_1",
        created_at: 1234567890,
      };
      expect(line.type).toBe("header");
      expect(line.id).toBe("session_1");
      expect(line.created_at).toBe(1234567890);
    });

    it("should allow optional fields", () => {
      const line: SessionHeaderLine = {
        type: "header",
        id: "session_1",
        created_at: 1234567890,
        continuation_variant: "manual",
        max_turns: 10,
        title: "Test",
      };
      expect(line.continuation_variant).toBe("manual");
      expect(line.max_turns).toBe(10);
      expect(line.title).toBe("Test");
    });
  });

  describe("MessageLine", () => {
    it("should have required fields", () => {
      const line: MessageLine = {
        type: "message",
        role: "user",
        content: "test",
      };
      expect(line.type).toBe("message");
      expect(line.role).toBe("user");
      expect(line.content).toBe("test");
    });

    it("should allow optional fields", () => {
      const line: MessageLine = {
        type: "message",
        role: "assistant",
        content: "test",
        tool_calls: [{ id: "call_1", type: "function", function: { name: "fn", arguments: "{}" } }],
        tool_call_id: "call_1",
        name: "test",
        annotations: [{ type: "test" }],
      };
      expect(line.tool_calls).toBeDefined();
      expect(line.tool_call_id).toBe("call_1");
      expect(line.name).toBe("test");
      expect(line.annotations).toBeDefined();
    });
  });

  describe("CheckpointLine", () => {
    it("should have required fields", () => {
      const line: CheckpointLine = {
        type: "checkpoint",
        checkpoint: "checkpoint_1",
        timestamp: 1234567890,
      };
      expect(line.type).toBe("checkpoint");
      expect(line.checkpoint).toBe("checkpoint_1");
      expect(line.timestamp).toBe(1234567890);
    });

    it("should allow optional metadata", () => {
      const line: CheckpointLine = {
        type: "checkpoint",
        checkpoint: "checkpoint_1",
        timestamp: 1234567890,
        metadata: { key: "value" },
      };
      expect(line.metadata).toEqual({ key: "value" });
    });
  });

  describe("SessionFileLine", () => {
    it("should be a union type", () => {
      const headerLine: SessionFileLine = {
        type: "header",
        id: "session_1",
        created_at: 1234567890,
      };
      expect(headerLine.type).toBe("header");

      const messageLine: SessionFileLine = {
        type: "message",
        role: "user",
        content: "test",
      };
      expect(messageLine.type).toBe("message");

      const checkpointLine: SessionFileLine = {
        type: "checkpoint",
        checkpoint: "checkpoint_1",
        timestamp: 1234567890,
      };
      expect(checkpointLine.type).toBe("checkpoint");
    });
  });

  describe("CompactionSummary", () => {
    it("should have required fields", () => {
      const summary: CompactionSummary = {
        before_token_count: 1000,
        after_token_count: 500,
        messages_removed: 10,
        checkpoints_removed: 2,
      };
      expect(summary.before_token_count).toBe(1000);
      expect(summary.after_token_count).toBe(500);
      expect(summary.messages_removed).toBe(10);
      expect(summary.checkpoints_removed).toBe(2);
    });

    it("should allow optional fields", () => {
      const summary: CompactionSummary = {
        before_token_count: 1000,
        after_token_count: 500,
        messages_removed: 10,
        checkpoints_removed: 2,
        duration_ms: 100,
        preserved_message_indices: [0, 1, 2],
        preserved_checkpoint_indices: [0],
      };
      expect(summary.duration_ms).toBe(100);
      expect(summary.preserved_message_indices).toEqual([0, 1, 2]);
      expect(summary.preserved_checkpoint_indices).toEqual([0]);
    });
  });

  describe("CompactionSegment", () => {
    it("should have required fields", () => {
      const segment: CompactionSegment = {
        type: "messages",
        items: [],
      };
      expect(segment.type).toBe("messages");
      expect(segment.items).toEqual([]);
    });

    it("should support checkpoint segment type", () => {
      const segment: CompactionSegment = {
        type: "checkpoints",
        items: [],
      };
      expect(segment.type).toBe("checkpoints");
    });

    it("should allow optional fields", () => {
      const segment: CompactionSegment = {
        type: "messages",
        items: [],
        token_count: 100,
        start_index: 0,
        end_index: 10,
      };
      expect(segment.token_count).toBe(100);
      expect(segment.start_index).toBe(0);
      expect(segment.end_index).toBe(10);
    });
  });

  describe("PreparedCompactionSegment", () => {
    it("should have required fields", () => {
      const segment: PreparedCompactionSegment = {
        type: "messages",
        items: [],
      };
      expect(segment.type).toBe("messages");
      expect(segment.items).toEqual([]);
    });

    it("should allow optional token count", () => {
      const segment: PreparedCompactionSegment = {
        type: "checkpoints",
        items: [],
        total_token_count: 500,
      };
      expect(segment.total_token_count).toBe(500);
    });
  });

  describe("PreparedCompaction", () => {
    it("should have required fields", () => {
      const compaction: PreparedCompaction = {
        messages: { type: "messages", items: [] },
        checkpoints: { type: "checkpoints", items: [] },
        metadata: { id: "test", created_at: 1234567890 },
      };
      expect(compaction.messages).toBeDefined();
      expect(compaction.checkpoints).toBeDefined();
      expect(compaction.metadata).toBeDefined();
    });

    it("should allow optional session header", () => {
      const compaction: PreparedCompaction = {
        messages: { type: "messages", items: [] },
        checkpoints: { type: "checkpoints", items: [] },
        metadata: { id: "test", created_at: 1234567890 },
        session_header: { id: "session_1", created_at: 1234567890 },
      };
      expect(compaction.session_header).toBeDefined();
    });

    it("should allow optional structured state", () => {
      const compaction: PreparedCompaction = {
        messages: { type: "messages", items: [] },
        checkpoints: { type: "checkpoints", items: [] },
        metadata: { id: "test", created_at: 1234567890 },
        structured_state: { todos: [] },
      };
      expect(compaction.structured_state).toBeDefined();
    });
  });

  describe("type compatibility", () => {
    it("Message should be compatible with MessageLine", () => {
      const msg: Message = { role: "user", content: "test" };
      const line: MessageLine = { type: "message", role: "user", content: "test" };
      expect(msg.role).toBe(line.role);
      expect(msg.content).toBe(line.content);
    });

    it("CheckpointMessage should be compatible with CheckpointLine", () => {
      const checkpoint: CheckpointMessage = { checkpoint: "cp1", timestamp: 123 };
      const line: CheckpointLine = { type: "checkpoint", checkpoint: "cp1", timestamp: 123 };
      expect(checkpoint.checkpoint).toBe(line.checkpoint);
      expect(checkpoint.timestamp).toBe(line.timestamp);
    });

    it("SessionMetadata should be compatible with SessionHeaderLine", () => {
      const meta: SessionMetadata = { id: "session_1", created_at: 123 };
      const line: SessionHeaderLine = { type: "header", id: "session_1", created_at: 123 };
      expect(meta.id).toBe(line.id);
      expect(meta.created_at).toBe(line.created_at);
    });

    it("PreparedCompaction should be compatible with PreparedCompactionV2", () => {
      const v2: PreparedCompactionV2 = {
        messages: [],
        checkpoints: [],
        metadata: { id: "test", created_at: 123 },
      };
      const v1: PreparedCompaction = {
        messages: { type: "messages", items: [] },
        checkpoints: { type: "checkpoints", items: [] },
        metadata: { id: "test", created_at: 123 },
      };
      expect(v2.metadata.id).toBe(v1.metadata.id);
    });

    it("ActualTokenUsageInput should be compatible with ActualTokenUsage", () => {
      const input: ActualTokenUsageInput = { prompt_tokens: 100, completion_tokens: 50 };
      const usage: ActualTokenUsage = { prompt_tokens: 100, completion_tokens: 50, total_tokens: 150 };
      expect(input.prompt_tokens).toBe(usage.prompt_tokens);
      expect(input.completion_tokens).toBe(usage.completion_tokens);
    });
  });
});
